'use client';

import { usePathname, useRouter, useSearchParams } from 'next/navigation';
import { Search, Loader2 } from 'lucide-react';
import { useTransition, useEffect, useState } from 'react';

interface SearchInputProps {
  placeholder?: string;
  className?: string;
}

export function SearchInput({ 
  placeholder = 'Search...',
  className = ''
}: SearchInputProps) {
  const { replace } = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const [isPending, startTransition] = useTransition();
  const [value, setValue] = useState(searchParams.get('q')?.toString() || '');

  // Debounce search
  useEffect(() => {
    const timer = setTimeout(() => {
      const params = new URLSearchParams(searchParams);
      if (value) {
        params.set('q', value);
      } else {
        params.delete('q');
      }
      
      startTransition(() => {
        replace(`${pathname}?${params.toString()}`);
      });
    }, 400);

    return () => clearTimeout(timer);
  }, [value, pathname, replace, searchParams]);

  return (
    <div className={`relative group ${className}`}>
      {/* Decorative Glow */}
      <div className="absolute inset-0 bg-saffron/10 blur-2xl rounded-[2rem] opacity-0 group-focus-within:opacity-100 transition-opacity duration-700 pointer-events-none" />
      
      <div className="relative flex items-center">
        <Search 
          className={`absolute left-6 h-5 w-5 transition-all duration-500 ${
            value ? 'text-saffron' : 'text-white/20 group-focus-within:text-saffron'
          }`} 
        />
        <input
          type="text"
          className="w-full bg-white/[0.03] border border-white/10 rounded-[2rem] py-5 pl-16 pr-14 text-white placeholder:text-white/10 focus:outline-none focus:border-saffron/40 focus:bg-white/[0.06] transition-all duration-500 backdrop-blur-3xl shadow-2xl text-lg font-medium italic"
          placeholder={placeholder}
          value={value}
          onChange={(e) => setValue(e.target.value)}
        />
        
        {/* Loading Indicator or Clear Button logic can go here */}
        {isPending && (
          <div className="absolute right-6">
            <Loader2 className="h-5 w-5 animate-spin text-saffron/60" />
          </div>
        )}
      </div>
    </div>
  );
}
