'use client';

import { useTransition } from 'react';
import { Trash2, Loader2 } from 'lucide-react';
import { deletePodcast } from '@/app/actions/admin';
import { Button } from '@/components/ui/Button';

export default function DeletePodcastButton({ id }: { id: string }) {
  const [isPending, startTransition] = useTransition();

  const handleDelete = async () => {
    if (window.confirm('Are you sure you want to delete this podcast episode?')) {
      startTransition(async () => {
        const result = await deletePodcast(id);
        if (!result.success) {
          alert(result.error);
        }
      });
    }
  };

  return (
    <Button
      variant="ghost"
      size="icon"
      className="h-10 w-10 text-white/40 hover:text-red-400 hover:bg-red-400/10 rounded-xl transition-all"
      onClick={handleDelete}
      disabled={isPending}
    >
      {isPending ? <Loader2 size={18} className="animate-spin" /> : <Trash2 size={18} />}
    </Button>
  );
}
